      if (!q) return this.recentRecords;
      return this.recentRecords.filter(r => {
        const info = r.personalInformation || {};
        const op = r.operationDetails || {};
        return [info.firstName, info.middleName, info.lastName, info.alias, op.operationName].filter(Boolean).some(v => v.toLowerCase().includes(q));
