        return this.recentRecords.slice(0, this.bubbleDisplayLimit);
      }
      const sel = this.recentRecords.find(r => r._id === this.selectedBubbleRecordId);
      const rest = this.recentRecords.filter(r => r._id !== this.selectedBubbleRecordId);
      return [sel, ...rest].filter(Boolean).slice(0, this.bubbleDisplayLimit);
    },
    linkedOperationRecords() {
      const opName = this.selectedBubbleRecord?.operationDetails?.operationName?.trim();
      if (!opName) return [];
      return this.recentRecords.filter(r => r._id !== this.selectedBubbleRecordId && r.operationDetails?.operationName?.trim() === opName);
    }
  },
  components: {
    Icon
  },
  methods: {
