      this.isLoadingRecords = true;
      this.recordsError = "";
      try {
        const res = await API.get("/records");
        this.recentRecords = Array.isArray(res.data) ? res.data : [];
        this.selectedBubbleRecordId = this.selectedBubbleRecordId && this.recentRecords.some(r => r._id === this.selectedBubbleRecordId) ? this.selectedBubbleRecordId : this.recentRecords[0]?._id || "";
        this.initializeBubblePositions();
      } catch (err) {
        this.recordsError = err.response?.data?.message || "Unable to load registrations.";
      } finally {
        this.isLoadingRecords = false;
