      const columnGap = isSelected ? 11 : 14;
      const rowGap = isSelected ? 12 : 14;
      const baseLeft = isSelected ? 2 : 4;
      const baseTop = isSelected ? 5 : 4;
      const row = Math.floor(index / columns);
      const col = index % columns;
      const size = sizePattern[index % sizePattern.length];
      const leftOffset = row % 2 === 0 ? 0 : isSelected ? 4 : 3;
      const topOffset = isSelected ? [0, 3, 1, 4][col % 4] : col % 2 === 0 ? 0 : 2;
      return {
        top: `${baseTop + row * rowGap + topOffset}%`,
        left: `${baseLeft + col * columnGap + leftOffset}%`,
        size
      };
    },
