      const rect = board.getBoundingClientRect();
      this.activeBubbleDrag = {
        id: record._id,
        width: pos.width || pos.size,
        height: pos.height || pos.size,
        offsetX: event.clientX - rect.left - parseFloat(pos.left) / 100 * rect.width,
        offsetY: event.clientY - rect.top - parseFloat(pos.top) / 100 * rect.height
      };
    },
    handleBubbleDrag(event) {
      const board = this.$refs.bubbleBoard;
      const drag = this.activeBubbleDrag;
      if (!board || !drag) return;
      const rect = board.getBoundingClientRect();
      const maxX = Math.max(rect.width - drag.width, 0);
      const maxY = Math.max(rect.height - drag.height, 0);
      const nx = Math.min(Math.max(event.clientX - rect.left - drag.offsetX, 0), maxX);
      const ny = Math.min(Math.max(event.clientY - rect.top - drag.offsetY, 0), maxY);
      this.bubblePositions = {
        ...this.bubblePositions,
        [drag.id]: {
          top: `${ny / rect.height * 100}%`,
          left: `${nx / rect.width * 100}%`,
          width: drag.width,
          height: drag.height
        }
      };
    },
