      this.activeBubbleDrag = null;
    },
    isBubbleDragging(id) {
      return this.activeBubbleDrag?.id === id;
    }
  },
  mounted() {
    window.addEventListener("pointermove", this.handleBubbleDrag);
    window.addEventListener("pointerup", this.stopBubbleDrag);
    this.loadRecentRecords();
